---
---
<footer class="site-footer">
  <div class="footer-gradient"></div>
  <div class="footer-inner">
    <p>&copy; {new Date().getFullYear()} oozoofrog</p>
    <div class="footer-links">
      <a href="https://github.com/oozoofrog" target="_blank" rel="noopener noreferrer">
        <svg width="16" height="16" viewBox="0 0 16 16" fill="currentColor"><path d="M8 0C3.58 0 0 3.58 0 8c0 3.54 2.29 6.53 5.47 7.59.4.07.55-.17.55-.38 0-.19-.01-.82-.01-1.49-2.01.37-2.53-.49-2.69-.94-.09-.23-.48-.94-.82-1.13-.28-.15-.68-.52-.01-.53.63-.01 1.08.58 1.23.82.72 1.21 1.87.87 2.33.66.07-.52.28-.87.51-1.07-1.78-.2-3.64-.89-3.64-3.95 0-.87.31-1.59.82-2.15-.08-.2-.36-1.02.08-2.12 0 0 .67-.21 2.2.82.64-.18 1.32-.27 2-.27.68 0 1.36.09 2 .27 1.53-1.04 2.2-.82 2.2-.82.44 1.1.16 1.92.08 2.12.51.56.82 1.27.82 2.15 0 3.07-1.87 3.75-3.65 3.95.29.25.54.73.54 1.48 0 1.07-.01 1.93-.01 2.2 0 .21.15.46.55.38A8.013 8.013 0 0016 8c0-4.42-3.58-8-8-8z"/></svg>
        GitHub
      </a>
      <a href="mailto:oozoofrog@gmail.com">
        ✉ Email
      </a>
    </div>
    <p class="footer-credit">Built with Astro</p>
  </div>
</footer>

<style>
  .site-footer {
    background: rgba(255, 255, 255, 0.35);
    backdrop-filter: blur(16px);
    -webkit-backdrop-filter: blur(16px);
    padding: 40px 20px;
    margin-top: 40px;
    text-align: center;
    color: #8a9a92;
    font-size: 0.85em;
    position: relative;
    border-top: 1px solid rgba(255, 255, 255, 0.4);
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.5);
  }

  .footer-gradient {
    display: none;
  }

  .footer-inner {
    max-width: 800px;
    margin: 0 auto;
    display: flex;
    justify-content: space-between;
    align-items: center;
  }

  .footer-links {
    display: flex;
    gap: 16px;
  }

  .footer-links a {
    color: #8a9a92;
    text-decoration: none;
    display: flex;
    align-items: center;
    gap: 4px;
  }

  .footer-links a:hover {
    color: var(--frog-green);
  }

  .footer-credit {
    color: #b0c0b8;
    font-size: 0.85em;
  }

  @media (max-width: 600px) {
    .footer-inner {
      flex-direction: column;
      gap: 8px;
    }
  }
</style>

