  1→---
  2→import BaseLayout from '../../layouts/BaseLayout.astro';
  3→import { getCollection } from 'astro:content';
  4→import { categories, getCategory } from '../../data/categories';
  5→
  6→const posts = (await getCollection('blog'))
  7→  .sort((a, b) => b.data.date.getTime() - a.data.date.getTime());
  8→
  9→const categoryCounts: Record<string, number> = { all: posts.length };
 10→for (const post of posts) {
 11→  const cat = getCategory(post.id);
 12→  categoryCounts[cat] = (categoryCounts[cat] ?? 0) + 1;
 13→}
 14→---
 15→
 16→<BaseLayout title="Blog">
 17→  <h1>Blog</h1>
 18→
 19→  <div class="filter-bar">
 20→    {categories.map(cat => (
 21→      <button
 22→        class={`filter-pill${cat.key === 'all' ? ' active' : ''}`}
 23→        data-filter={cat.key}
 24→      >
 25→        {cat.label} <span class="pill-count">{categoryCounts[cat.key] ?? 0}</span>
 26→      </button>
 27→    ))}
 28→  </div>
 29→
 30→  <ul class="post-list">
 31→    {posts.map(post => (
 32→      <li data-category={getCategory(post.id)}>
 33→        <time datetime={post.data.date.toISOString()}>
 34→          {post.data.date.toISOString().slice(0, 10)}
 35→        </time>
 36→        <a href={`/blog/${post.id}/`}>{post.data.title}</a>
 37→      </li>
 38→    ))}
 39→  </ul>
 40→</BaseLayout>
 41→
 42→<style>
 43→  h1 {
 44→    margin-bottom: 1.5rem;
 45→  }
 46→
 47→  .filter-bar {
 48→    display: flex;
 49→    gap: 8px;
 50→    margin-bottom: 1.5rem;
 51→    overflow-x: auto;
 52→    -webkit-overflow-scrolling: touch;
 53→    scrollbar-width: none;
 54→    padding-bottom: 4px;
 55→  }
 56→
 57→  .filter-bar::-webkit-scrollbar {
 58→    display: none;
 59→  }
 60→
 61→  .filter-pill {
 62→    display: inline-flex;
 63→    align-items: center;
 64→    gap: 6px;
 65→    padding: 6px 16px;
 66→    border-radius: 20px;
 67→    font-size: 0.85rem;
 68→    font-weight: 600;
 69→    white-space: nowrap;
 70→    cursor: pointer;
 71→    border: 1px solid rgba(255, 255, 255, 0.6);
 72→    background: rgba(255, 255, 255, 0.45);
 73→    color: var(--dark-green);
 74→    transition: background 0.15s, color 0.15s, border-color 0.15s;
 75→  }
 76→
 77→  @supports (backdrop-filter: blur(8px)) {
 78→    .filter-pill {
 79→      backdrop-filter: blur(8px);
 80→    }
 81→  }
 82→
 83→  .filter-pill:hover {
 84→    background: rgba(91, 168, 71, 0.15);
 85→    border-color: var(--frog-green);
 86→  }
 87→
 88→  .filter-pill.active {
 89→    background: var(--frog-green);
 90→    color: #fff;
 91→    border-color: var(--frog-green);
 92→  }
 93→
 94→  .pill-count {
 95→    font-weight: 400;
 96→    opacity: 0.8;
 97→    font-size: 0.8rem;
 98→  }
 99→
100→  .post-list {
101→    list-style: none;
102→    padding: 0;
103→  }
104→
105→  .post-list li {
106→    display: flex;
107→    gap: 1rem;
108→    align-items: baseline;
109→    padding: 0.75rem 0;
110→    border-bottom: 1px solid var(--border);
111→  }
