    .privacy-policy {
      background: rgba(255, 255, 255, 0.75);
    }
  }

  h1 {
    font-size: 2.2em;
    color: var(--dark-green);
    margin-bottom: 8px;
    padding-bottom: 16px;
    border-bottom: 3px solid var(--frog-green);
  }

  .last-updated {
    color: #8a9a92;
    font-size: 0.9em;
    margin-bottom: 40px;
  }

  section {
    margin-bottom: 40px;
