    left: 0;
    top: 50%;
    transform: translateY(-50%);
    width: 4px;
    height: 1.2em;
    background: var(--frog-green);
    border-radius: 2px;
  }

  h3 {
    font-size: 1.15em;
    color: var(--dark-green);
    margin-bottom: 12px;
    margin-top: 20px;
