    color: var(--dark-green);
    margin-bottom: 40px;
    padding-bottom: 16px;
    border-bottom: 3px solid var(--frog-green);
  }

  section {
    margin-bottom: 40px;
  }

  h2 {
    font-size: 1.5em;
    color: var(--dark-green);
    margin-bottom: 16px;
    position: relative;
    padding-left: 16px;
  }

  h2::before {
    content: '';
    position: absolute;
    left: 0;
    top: 50%;
    transform: translateY(-50%);
    width: 4px;
    height: 1.2em;
    background: var(--frog-green);
    border-radius: 2px;
  }

  p {
    color: #333;
    line-height: 1.8;
    margin-bottom: 12px;
  }

  .contact-cards {
    display: flex;
    gap: 20px;
    margin-top: 20px;
    flex-wrap: wrap;
  }

  .contact-card {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 8px;
    padding: 24px 32px;
    background: rgba(255, 255, 255, 0.5);
    border: 1px solid rgba(255, 255, 255, 0.6);
    border-radius: 12px;
    text-decoration: none;
    color: #333;
    transition: all 0.2s ease;
    flex: 1;
    min-width: 200px;
  }

  .contact-card:hover {
    transform: translateY(-2px);
    background: rgba(255, 255, 255, 0.7);
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.08);
    border-color: var(--frog-green);
  }

  .contact-icon {
    font-size: 1.5em;
    color: var(--frog-green);
    display: flex;
    align-items: center;
  }

  .contact-icon svg {
    fill: var(--frog-green);
  }

  .contact-label {
    font-weight: 600;
    color: var(--dark-green);
    font-size: 1.1em;
  }

  .contact-value {
    color: #666;
    font-size: 0.9em;
  }

  a {
    color: var(--frog-green);
    text-decoration: none;
    border-bottom: 1.5px solid transparent;
    transition: color 0.2s ease, border-bottom 0.2s ease;
  }

  a:hover {
    color: var(--planet-orange);
    border-bottom: 1.5px solid var(--planet-orange);
  }

  .page-nav {
    display: flex;
    gap: 16px;
    margin-top: 60px;
    padding-top: 40px;
    border-top: 1px solid #e0ebe6;
    flex-wrap: wrap;
  }

  .nav-link {
    display: inline-block;
    padding: 10px 20px;
    background: rgba(112, 168, 80, 0.75);
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    color: #fff;
    border: 1px solid rgba(255, 255, 255, 0.3);
    border-radius: 20px;
    font-weight: 600;
    transition: all 0.15s;
    box-shadow: 0 4px 12px rgba(45, 80, 22, 0.15), inset 0 1px 0 rgba(255, 255, 255, 0.2);
  }

  .nav-link:hover {
    transform: translateY(-2px);
    background: rgba(112, 168, 80, 0.85);
    box-shadow: 0 6px 20px rgba(45, 80, 22, 0.25), inset 0 1px 0 rgba(255, 255, 255, 0.3);
    border-bottom: 1px solid rgba(255, 255, 255, 0.3);
  }

  @supports not (backdrop-filter: blur(12px)) {
    .nav-link {
      background: rgba(112, 168, 80, 0.9);
    }
  }

  @media (max-width: 600px) {
    .contact-page {
      padding: 24px 16px;
    }

    h1 {
      font-size: 1.8em;
    }

    h2 {
      font-size: 1.3em;
    }

    .contact-cards {
      flex-direction: column;
    }

    .page-nav {
      flex-direction: column;
    }

    .nav-link {
      text-align: center;
    }
  }
</style>

